VALUES
  ('streak_at_risk', 'ar', 'حافظ على السلسلة حية 🔥', 'وصل خط {type} الخاص بك إلى {streak} من الأيام. نقرة أخرى قبل منتصف الليل ستؤدي إلى قفله.', 'quran'),
  ('streak_at_risk', 'ur', 'زنجیر کو زندہ رکھیں 🔥', 'آپ کا {type} سلسلہ ہٹ {streak} دن۔ آدھی رات سے پہلے ایک اور تھپتھپائیں اسے لاک کر دیں۔', 'quran'),
  ('streak_at_risk', 'fr', 'Gardez la chaîne en vie 🔥', 'Votre séquence {type} a atteint {streak} jours. Un clic de plus avant minuit le verrouille.', 'quran'),
  ('streak_at_risk', 'id', 'Jaga agar rantai tetap hidup 🔥', 'Pukulan {type} Anda mencapai {streak} hari. Satu ketukan lagi sebelum tengah malam akan menguncinya.', 'quran'),
  ('streak_at_risk', 'ms', 'Pastikan rantai itu hidup 🔥', '{type} coretan anda mencecah {streak} hari. Satu ketik lagi sebelum tengah malam menguncinya.', 'quran'),
  ('streak_at_risk', 'ru', 'Сохраняйте цепочку 🔥', 'Ваша серия {type} длилась {streak} дней. Еще одно нажатие до полуночи, и оно заблокируется.', 'quran'),
  ('streak_at_risk', 'tr', 'Zinciri canlı tutun 🔥', '{type} seriniz {streak} güne ulaştı. Gece yarısından önce bir dokunuş daha onu kilitler.', 'quran'),
  ('streak_at_risk', 'ar', '{streak} أيام قوية - لا تتوقف الآن', 'لقد قطعت شوطا طويلا لكسر خط {type} الخاص بك. افتح سابق واختم اليوم.', 'quran'),
  ('streak_at_risk', 'ur', '{streak} دن مضبوط — اب مت روکو', 'آپ اپنے {type} سلسلے کو توڑنے کے لیے بہت دور آ گئے ہیں۔ آج صابق کو کھول کر مہر لگا دیں۔', 'quran'),
  ('streak_at_risk', 'fr', '{streak} jours forts - ne vous arrêtez pas maintenant', 'Vous êtes allé trop loin pour mettre fin à votre séquence {type}. Ouvrez Sabiq et scellez-le aujourd''hui.', 'quran'),
  ('streak_at_risk', 'id', '{streak} hari yang kuat — jangan berhenti sekarang', 'Anda telah melangkah terlalu jauh untuk mematahkan pukulan {type} Anda. Buka Sabiq dan segel hari ini.', 'quran'),
  ('streak_at_risk', 'ms', '{streak} hari kuat — jangan berhenti sekarang', 'Anda telah melangkah terlalu jauh untuk memecahkan rentetan {type} anda. Buka Sabiq dan tutup hari ini.', 'quran'),
  ('streak_at_risk', 'ru', '{streak} дней сильных — не останавливайтесь сейчас', 'Вы зашли слишком далеко, чтобы прервать серию {type}. Откройте Сабик и запечатайте сегодня.', 'quran'),
  ('streak_at_risk', 'tr', '{streak} güçlü günler — şimdi durma', '{type} serinizi kıramayacak kadar ileri geldiniz. Bugün Sabiq''i açın ve mühürleyin.', 'quran'),
  ('streak_at_risk', 'ar', 'الليلة مهمة', 'تخطي اليوم و{streak} أيام من {type} تتم إعادة تعيينها إلى الصفر. دقيقتين تحفظه', 'quran'),
  ('streak_at_risk', 'ur', 'آج رات اہمیت رکھتی ہے۔', 'آج کو چھوڑ دیں اور {type} کے {streak} دن صفر پر ری سیٹ ہو جائیں۔ دو منٹ اسے بچاتا ہے۔', 'quran'),
  ('streak_at_risk', 'fr', 'Ce soir compte', 'Sautez aujourd''hui et {streak} jours de {type} seront réinitialisés à zéro. Deux minutes le sauvent.', 'quran'),
  ('streak_at_risk', 'id', 'Malam ini penting', 'Lewati hari ini dan {streak} hari dari {type} direset ke nol. Dua menit menghematnya.', 'quran'),
  ('streak_at_risk', 'ms', 'Malam ini penting', 'Langkau hari ini dan {streak} hari {type} ditetapkan semula kepada sifar. Dua minit menyimpannya.', 'quran'),
  ('streak_at_risk', 'ru', 'Сегодня вечером важно', 'Пропустите сегодняшний день, и {streak} дней из {type} обнулится. Две минуты спасают ситуацию.', 'quran'),
  ('streak_at_risk', 'tr', 'Bu gece önemli', 'Bugünü atlayın ve {type} gününün {streak} günü sıfıra sıfırlanır. İki dakika kurtarır.', 'quran'),
