  ('streak_at_risk', 'ur', 'آپ کا سلسلہ خطرے میں ہے۔', '{type} کے {streak} دن لائن پر ہیں۔ گھڑی گھمنے سے پہلے صابق کو کھولو۔', 'quran'),
  ('streak_at_risk', 'fr', 'Votre séquence est en danger', '{streak} jours de {type} sont en jeu. Ouvrez Sabiq avant que l''horloge ne tourne.', 'quran'),
